+// Check if a division instruction feeds into any GetElementPtrInst within the loop.
+static bool divFeedsIntoGEP(Instruction *DivInst, const Loop *TheLoop) {
+  SmallPtrSet<Instruction *, 16> Visited;
+  SmallVector<Instruction *, 16> Worklist;
+  Worklist.push_back(DivInst);
+  
+  while (!Worklist.empty()) {
+    Instruction *I = Worklist.pop_back_val();
+    if (!Visited.insert(I).second)
+      continue;
+      
+    // If this is a GEP inside the loop, we found a dependency
+    if (isa<GetElementPtrInst>(I) && TheLoop->contains(I->getParent()))
+      return true;
+      
+    // Continue searching through users
+    for (User *U : I->users()) {
+      if (Instruction *UI = dyn_cast<Instruction>(U))
+        Worklist.push_back(UI);
+    }
+  }
+  return false;
+}
